 class=\"fn\">WriteLine</span>(<span class=\"st\">$\"Email: {{msg}}\"</span>);\n}\n\n<span class=\"kw\">public abstract class</span> <span class=\"cl\">Creator</span> {\n  <span class=\"kw\">public abstract</span> <span class=\"cl\">INotifier</span> <span class=\"fn\">Create</span>();\n  <span class=\"kw\">public void</span> <span class=\"fn\">Notify</span>(<span class=\"kw\">string</span> <span class=\"dc\">msg</span>) =&gt;\n    <span class=\"fn\">Create</span>().<span class=\"fn\">Send</span>(<span class=\"dc\">msg</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">EmailCreator</span> : <span class=\"cl\">Creator</span> {\n  <span class=\"kw\">public override</span> <span class=\"cl\">INotifier</span> <span class=\"fn\">Create</span>() =&gt;\n    <span class=\"kw\">new</span> <span class=\"cl\">EmailNotifier</span>();\n}", "Python": "<span class=\"kw\">from</span> abc <span class=\"kw\">import</span> <span class=\"cl\">ABC</span>, abstractmethod\n\n<span class=\"kw\">class</span> <span class=\"cl\">Creator</span>(<span class=\"cl\">ABC</span>):\n  <span class=\"dc\">@abstractmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">create</span>(<span class=\"dc\">self</span>): ...\n\n  <span class=\"kw\">def</span> <span class=\"fn\">notify</span>(<span class=\"dc\">self</span>, <span class=\"dc\">msg</span>):\n    <span class=\"dc\">self</span>.<span class=\"fn\">create</span>().<span class=\"fn\">send</span>(<span class=\"dc\">msg</span>)\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">Email</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">send</span>(<span class=\"dc\">self</span>, <span class=\"dc\">msg</span>):\n    <span class=\"fn\">print</span>(<span class=\"st\">f\"Email: {{msg}}\"</span>)\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">EmailCreator</span>(<span class=\"cl\">Creator</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">create</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return</span> <span class=\"cl\">Email</span>()", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">Creator</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">create</span> = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">notify</span>(<span class=\"dc\">msg</span>) = <span class=\"fn\">create</span>.<span class=\"fn\">send_msg</span>(<span class=\"dc\">msg</span>)\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">Email</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">send_msg</span>(<span class=\"dc\">msg</span>) = <span class=\"fn\">puts</span> <span class=\"st\">\"Email: #{{msg}}\"</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">EmailCreator</span> &lt; <span class=\"cl\">Creator</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">create</span> = <span class=\"cl\">Email</span>.<span class=\"fn\">new</span>\n<span class=\"kw\">end</span>"}

